function Topo { Clear-Host; $host.UI.RawUI.WindowTitle = "Monitoramento Internet"; $global:largura = $host.UI.RawUI.WindowSize.Width; Write-Host ("=" * ($global:largura - 1)) -ForegroundColor Green; Write-Host "" }; Topo; $enviados = 0; $recebidos = 0; try { while ($true) { $enviados++; $res = Test-Connection 8.8.8.8 -Count 1 -ErrorAction SilentlyContinue; $data = Get-Date -Format "dd/MM/yyyy HH:mm:ss"; if ($res) { $recebidos++; $perda = [math]::Round((($enviados - $recebidos) / $enviados) * 100, 1); Write-Host "$data" -ForegroundColor Green -NoNewline; Write-Host " -> " -ForegroundColor DarkGray -NoNewline; Write-Host "Destino: " -ForegroundColor Green -NoNewline; Write-Host "8.8.8.8" -ForegroundColor Yellow -NoNewline; Write-Host " -> " -ForegroundColor DarkGray -NoNewline; Write-Host "Latencia: $($res.ResponseTime)ms" -ForegroundColor Gray -NoNewline; Write-Host " | " -ForegroundColor DarkGray -NoNewline; Write-Host "[" -ForegroundColor DarkGray -NoNewline; Write-Host "Enviados: $enviados" -ForegroundColor Cyan -NoNewline; Write-Host " | " -ForegroundColor DarkGray -NoNewline; Write-Host "Perdidos: $($enviados - $recebidos)" -ForegroundColor DarkYellow -NoNewline; Write-Host " | " -ForegroundColor DarkGray -NoNewline; Write-Host "Perda: $perda%" -ForegroundColor Red -NoNewline; Write-Host "]" -ForegroundColor DarkGray } else { $perda = [math]::Round((($enviados - $recebidos) / $enviados) * 100, 1); Write-Host "$data" -ForegroundColor Green -NoNewline; Write-Host " -> " -ForegroundColor DarkGray -NoNewline; Write-Host "Destino: " -ForegroundColor Green -NoNewline; Write-Host "8.8.8.8" -ForegroundColor Yellow -NoNewline; Write-Host " -> " -ForegroundColor DarkGray -NoNewline; Write-Host "FALHA (Timeout)" -ForegroundColor Green -NoNewline; Write-Host " | " -ForegroundColor DarkGray -NoNewline; Write-Host "[" -ForegroundColor DarkGray -NoNewline; Write-Host "Enviados: $enviados" -ForegroundColor Cyan -NoNewline; Write-Host " | " -ForegroundColor DarkGray -NoNewline; Write-Host "Perdidos: $($enviados - $recebidos)" -ForegroundColor DarkYellow -NoNewline; Write-Host " | " -ForegroundColor DarkGray -NoNewline; Write-Host "Perda: $perda%" -ForegroundColor Red -NoNewline; Write-Host "]" -ForegroundColor DarkGray }; Start-Sleep -Seconds 1 } } finally { Write-Host ""; Write-Host ("=" * ($global:largura - 1)) -ForegroundColor Green; Write-Host " MONITORAMENTO ENCERRADO PELO USUÁRIO" -ForegroundColor Green; Write-Host ("=" * ($global:largura - 1)) -ForegroundColor Green }